public class Chain {
    abstract static class Handler {
        Handler next;
        Handler setNext(Handler h) { next = h; return h; }
        abstract void handle(int req);
        void passOn(int req) { if (next != null) next.handle(req); }
    }
    static class SmallHandler extends Handler {
        void handle(int req) { if (req < 10) System.out.println("Small:" + req); else passOn(req); }
    }
    static class BigHandler extends Handler {
        void handle(int req) { System.out.println("Big:" + req); }
    }
    public static void main(String[] args) {
        SmallHandler s = new SmallHandler();
        s.setNext(new BigHandler());
        s.handle(5);
        s.handle(20);
        s.handle(3);
    }
}
